class TestIdentityTransform:
    def test_transform(self):
        t = IdentityTransform()
        assert t.transform([1, 2]) == [1, 2]

    def test_inverted(self):
        t = IdentityTransform()
        ti = t.inverted()
        assert isinstance(ti, IdentityTransform)

    def test_is_affine(self):
        t = IdentityTransform()
        assert t.is_affine

    def test_repr(self):
        t = IdentityTransform()
        r = repr(t)
        assert 'Identity' in r


# ------------------------------------------------------------------
# Rectangle patch tests
# ------------------------------------------------------------------

class TestRectangle:
    def test_creation(self):
        r = Rectangle((0, 0), 1, 2)
        assert r is not None

    def test_get_xy(self):
        r = Rectangle((3, 4), 1, 2)
        xy = r.get_xy()
        assert close(xy[0], 3)
        assert close(xy[1], 4)

    def test_get_width(self):
        r = Rectangle((0, 0), 5, 3)
        assert close(r.get_width(), 5)

    def test_get_height(self):
        r = Rectangle((0, 0), 5, 3)
        assert close(r.get_height(), 3)

    def test_set_xy(self):
        r = Rectangle((0, 0), 1, 1)
        r.set_xy((2, 3))
        xy = r.get_xy()
        assert close(xy[0], 2)
        assert close(xy[1], 3)

    def test_set_width(self):
        r = Rectangle((0, 0), 1, 1)
        r.set_width(7)
        assert close(r.get_width(), 7)

    def test_set_height(self):
        r = Rectangle((0, 0), 1, 1)
        r.set_height(9)
        assert close(r.get_height(), 9)

    def test_facecolor(self):
        r = Rectangle((0, 0), 1, 1, facecolor='red')
        fc = r.get_facecolor()
        assert len(fc) == 4
        assert close(fc[0], 1.0)  # red channel

    def test_edgecolor(self):
        r = Rectangle((0, 0), 1, 1, edgecolor='blue')
        ec = r.get_edgecolor()
        assert len(ec) == 4

    def test_linewidth(self):
        r = Rectangle((0, 0), 1, 1, linewidth=2)
        assert close(r.get_linewidth(), 2)

    def test_visible(self):
        r = Rectangle((0, 0), 1, 1)
        assert r.get_visible()
        r.set_visible(False)
        assert not r.get_visible()


